  warnings: { bg: 'rgba(193, 80, 28, 0.10)',       border: '#c1501c', color: '#c1501c', label: 'warnings' },
  failed:   { bg: '#1a2332',                        border: '#1a2332', color: '#f5efe2', label: 'failed' },
  queued:   { bg: 'rgba(26, 35, 50, 0.06)',        border: '#1a2332', color: '#1a2332', label: 'queued' },
  
