function StatStrip({ stats }) {
  // Each stat: { label, value, sublabel?, accent? }
  return (
    <div style={{
      display: 'grid',
      gridTemplateColumns: `repeat(${stats.length}, 1fr)`,
      borderTop: '0.5px solid #1a2332',
      borderBottom: '0.5px solid #1a2332',
      marginBottom: 24, background: '#fdf9ee',
    }}>
      {stats.map((s, i) => (
        <div key={i} style={{
          padding: '10px 14px',
          borderRight: i < stats.length - 1 ? '0.5px solid #1a2332' : 'none',
        }}>
          <div style={{
            fontFamily: 'JetBrains Mono, monospace', fontSize: 9,
            letterSpacing: '0.18em', opacity: 0.55, marginBottom: 4,
          }}>
            {s.label}
          </div>
          <div style={{
            fontFamily: 'EB Garamond, serif',
            fontSize: 24, lineHeight: 1, color: s.accent || '#1a2332',
          }}>
            {s.value}
          </div>
          {s.sublabel && (
            <div style={{
              fontFamily: 'JetBrains Mono, monospace', fontSize: 9,
              opacity: 0.6, marginTop: 4,
            }}>
              {s.sublabel}
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

function SectionHeader({ children, hint }) {
  return (
    <div style={{
      display: 'flex', alignItems: 'baseline', gap: 12,
      borderBottom: '0.5px solid #1a2332',
      paddingBottom: 6, marginBottom: 14,
    }}>
      <div style={{
        fontFamily: 'JetBrains Mono, monospace', fontSize: 9.5,
        letterSpacing: '0.22em',
      }}>
        ── {children} ──
      </div>
      {hint && (
        <div style={{
          fontFamily: 'EB Garamond, serif', fontSize: 13,
          fontStyle: 'italic', opacity: 0.65,
        }}>
          {hint}
        </div>
      )}
    </div>
  );
}

