function IntegrationsTab() {
  const grouped = useMemo(() => {
    const g = {};
    CONNECTIONS.forEach(c => {
      g[c.kind] = g[c.kind] || [];
      g[c.kind].push(c);
    });
    return g;
  }, []);
  
  const order = ['LMS', 'IDP', 'HRIS', 'LRS', 'Pod Federation', 'Manual'];
  
  return (
    <div>
      <div style={{
        fontFamily: 'EB Garamond, serif', fontSize: 14,
        marginBottom: 22, lineHeight: 1.55, maxWidth: '70ch',
      }}>
        Connections to source systems. Course content arrives via LMS APIs;
        users and groups via IDP (SAML/SCIM) and HRIS; learning records
        via LRS subscription; and primary-source content from authors
        publishes directly into your Solid pod federation.
      </div>
      
      {order.filter(k => grouped[k]).map(kind => (
        <div key={kind} style={{ marginBottom: 24 }}>
          <SectionHeader>{kind.toUpperCase()}</SectionHeader>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))',
            gap: 12,
          }}>
            {grouped[kind].map(c => <ConnectionCard key={c.id} connection={c} />)}
          </div>
        </div>
      ))}
      
      <div style={{
        marginTop: 22, padding: '16px 18px',
        border: '0.5px dashed #1a2332', background: 'rgba(26, 35, 50, 0.02)',
        fontFamily: 'EB Garamond, serif', fontStyle: 'italic',
        fontSize: 13, opacity: 0.75, lineHeight: 1.5,
        display: 'flex', justifyContent: 'space-between',
        alignItems: 'center', gap: 14,
      }}>
        <span>Need to connect a system not listed? Custom OAuth, SAML, and SCIM connectors take ~3 days to certify.</span>
        <button style={primaryButtonStyle}>+ ADD INTEGRATION</button>
      </div>
    </div>
  );
}

