function AdminShell({ user, onSignOut }) {
  const [activeTab, setActiveTab] = useState('catalog');
  const [navOpen, setNavOpen] = useState(false);

  const tabs = [
    ['catalog',      'CATALOG',      CatalogTab],
    ['coverage',     'COVERAGE',     CoverageTab],
    ['access',       'ACCESS',       AccessTab],
    ['integrations', 'INTEGRATIONS', IntegrationsTab],
    ['audit',        'AUDIT',        AuditTab],
  ];
  
  const ActiveTab = tabs.find(t => t[0] === activeTab)[2];

  return (
    <div className="admin-root">
      {/* Top bar */}
      <header className="admin-topbar">
        <div className="admin-topbar-inner">
          <div style={{ display: 'flex', alignItems: 'center', gap: 14, minWidth: 0, flex: 1 }}>
            <button className="admin-mobile-menu" onClick={() => setNavOpen(o => !o)}>≡</button>
            <div style={{ minWidth: 0 }}>
              <div style={{
                fontFamily: 'JetBrains Mono, monospace', fontSize: 9,
                letterSpacing: '0.22em', opacity: 0.65,
              }}>
                FOXXI ⟢ ADMIN
              </div>
              <div style={{
                fontFamily: 'EB Garamond, serif', fontStyle: 'italic',
                fontSize: 18, color: '#f5efe2', lineHeight: 1.1,
                whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
              }}>
                {TENANT.tenant}
              </div>
            </div>
          </div>
          <div className="admin-user-block">
            <div style={{ textAlign: 'right' }}>
              <div style={{
                fontFamily: 'EB Garamond, serif', fontSize: 14,
                lineHeight: 1.15, color: '#f5efe2',
              }}>
                {user.name}
              </div>
              <div style={{
                fontFamily: 'JetBrains Mono, monospace', fontSize: 9,
                opacity: 0.65,
              }}>
                {user.job_title || 'Visitor'}
              </div>
            </div>
            <button onClick={onSignOut} style={{
              padding: '5px 10px',
              background: 'transparent', color: '#f5efe2',
              border: '1px solid #f5efe2',
              fontFamily: 'JetBrains Mono, monospace', fontSize: 9,
              letterSpacing: '0.12em', cursor: 'pointer',
            }}>
              SIGN OUT
            </button>
          </div>
        </div>
      </header>

      {/* Tab nav */}
      <nav className={`admin-tabnav ${navOpen ? 'open' : ''}`}>
        <div className="admin-tabnav-inner">
          {tabs.map(([key, label]) => (
            <button key={key} onClick={() => { setActiveTab(key); setNavOpen(false); }}
              className={`admin-tab ${activeTab === key ? 'active' : ''}`}>
              {label}
            </button>
          ))}
        </div>
      </nav>

      {/* Active tab pane */}
      <main className="admin-main">
        <ActiveTab />
      </main>
      
      {/* Backdrop when mobile drawer open */}
      {navOpen && (
        <div className="admin-backdrop"
             onClick={() => setNavOpen(false)} />
      )}

      {/* Footer */}
      <footer className="admin-footer">
        <div style={{
          fontFamily: 'JetBrains Mono, monospace', fontSize: 9,
          opacity: 0.5, lineHeight: 1.7,
        }}>
          <div>foxxi admin v0.1 · vocab v0.2.0 · parser v0.3.0</div>
          <div>tenant: {TENANT.tenant_id} · pod: <span style={{ wordBreak: 'break-all' }}>{TENANT.tenant_pod}</span></div>
          <div>signed in as <span style={{ color: '#c1501c' }}>{user.web_id}</span></div>
        </div>
      </footer>
    </div>
  );
}


